const e=document.createElement("script");e.src=chrome.runtime.getURL("dist/inpage.js");(document.head||document.documentElement).appendChild(e);e.onload=()=>e.remove();window.addEventListener("message",t=>{var n;if(t.source!==window||((n=t.data)==null?void 0:n.target)!=="octra-content")return;const{id:o,method:a,params:r}=t.data,d=window.location.origin;chrome.runtime.sendMessage({type:"DAPP_REQUEST",payload:{method:a,params:r,origin:d}},i=>{window.postMessage({target:"octra-inpage",id:o,response:i},"*")})});
